Script.Source:
					import sailpoint.object.Field;
					import sailpoint.object.Form;
					import org.apache.log4j.Logger;
					import sailpoint.tools.Util;

					Logger logger = Logger.getLogger("sailpoint.ascension.rules.voalte.scripts");
					List formFields = form.getEntireFields();
					if (formFields != null && !formFields.isEmpty()) {
						for (Field currentField : formFields) {
							String currentFieldName = currentField.getName();
							logger.debug("CurrentFieldName:" + currentFieldName);
							if (Util.isNotNullOrEmpty(currentFieldName)) {
								if (currentFieldName.endsWith("addComments")) {
									if (currentField.getValue()==false) {
										//logger.debug("Trying to update :" + field.getName() + " -as addComments is false");
										field.setRequired(false);
										field.setReadOnly(true);
										field.setValue(null);
									} else {
										field.setRequired(true);
										field.setReadOnly(false);
									}
								}
							}
						}
					}
					return false;
